export const TOURNAMENT_YEARS = [2000, 2001, 2002, 2003, 2004, 2005, 2006, 2007, 2008, 2009, 2010, 2011, 2012, 2013, 2014, 2015, 2016, 2017, 2018, 2019, 2021, 2022, 2023, 2024, 2025] as const;

export const POSITIONS = ['Point Guard', 'Shooting Guard', 'Forward', 'Forward', 'Center'] as const;
export const UNIQUE_POSITIONS = ['Point Guard', 'Shooting Guard', 'Forward', 'Center'] as const;

export function getPlayersByYearAndPosition(year: number, position: string): TournamentPlayer[] {
  return TOURNAMENT_PLAYERS.filter(p => p.year === year && p.position === position)
    .sort((a, b) => b.totalTournamentPts - a.totalTournamentPts);
}

export function getMaxScoreForYear(year: number): number {
  let max = 0;
  for (const pos of UNIQUE_POSITIONS) {
    const players = getPlayersByYearAndPosition(year, pos);
    if (players.length === 0) continue;
    if (pos === 'Forward') {
      max += players[0].totalTournamentPts + (players[1]?.totalTournamentPts || 0);
    } else {
      max += players[0].totalTournamentPts;
    }
  }
  return max;
}

export function getTeamLogoUrl(espnId: number): string {
  return `https://a.espncdn.com/i/teamlogos/ncaa/500/${espnId}.png`;
}
